// ================================================================
// EVENT-DRIVEN ROUTER — Prisma compatible
// Memvalidasi event dari bot, menentukan mode MONITORING/CLOSING,
// dan meneruskan ke branch yang sesuai.
// Field yang dikirim bot (src/services/discord.service.js):
//   eventType, threadId, ticketId, ticketType,
//   statusPengusulan, mode, threadName, authorName,
//   messageId, messageContent, parentId, timestamp
// ================================================================
const eventData = $input.first().json.body || $input.first().json;

// Validasi event type
if (eventData.eventType !== 'thread_activity') return [];
if (!eventData.threadId || !eventData.ticketId) return [];

// Validasi ticket type — Prisma schema hanya kenal TICKETING & INCIDENT
const ticketType = (eventData.ticketType || '').toUpperCase();
if (ticketType !== 'TICKETING' && ticketType !== 'INCIDENT') return [];

// ── Tentukan mode & status ─────────────────────────────────────
let mode   = null;
let status = null;

if (eventData.mode) {
  // Mode dikirim eksplisit dari bot (lebih reliable)
  mode = eventData.mode.toUpperCase();
} else {
  // Fallback: derive dari statusPengusulan
  // Prisma valid statuses: OPEN, PENDING, APPROVED, REJECTED,
  //                        DONE, INVESTIGASI, MITIGASI, RESOLVED
  const s = (eventData.statusPengusulan || '').toUpperCase();
  if (ticketType === 'INCIDENT') {
    mode   = s === 'RESOLVED' ? 'CLOSING' : 'MONITORING';
    status = s === 'RESOLVED' ? 'CLOSED'  : (s || 'OPEN');
  } else {
    // TICKETING
    mode   = s === 'DONE' ? 'CLOSING' : 'MONITORING';
    status = s === 'DONE' ? 'CLOSED'  : (s || 'OPEN');
  }
}

if (mode !== 'MONITORING' && mode !== 'CLOSING') return [];

// ── Build thread name ──────────────────────────────────────────
const typeLabel    = ticketType === 'INCIDENT' ? '[Incident]' : '[Support]';
const statusPrefix = mode === 'CLOSING' ? '[CLOSED]' : '[OPEN]';
const threadName   = eventData.threadName
  || `${statusPrefix} ${typeLabel} Ticket #${eventData.ticketId}`;

console.log(`✅ [WF1] Ticket #${eventData.ticketId} → mode=${mode} type=${ticketType}`);

return [{ json: {
  threadId:       eventData.threadId,
  threadName,
  ticketId:       eventData.ticketId,
  ticketType,
  mode,
  status:         status || eventData.statusPengusulan || 'OPEN',
  parentId:       eventData.parentId || null,
  eventTimestamp: eventData.timestamp,
  triggeredBy:    eventData.authorName,
  messageId:      eventData.messageId,
  triggerMessage: eventData.messageContent
}}];

// ================================================================
// EXTRACT (MONITOR MODE) — Strict Timeline Filter
// Prisma fix:
//   - Pinned message format identik (tidak berubah dari original)
//   - ticketInfo.ticketId diekstrak dari pinned message Discord
//   - Hanya action yang benar-benar selesai yang di-forward ke AI
// ================================================================
const messages = $input.all().map(i => i.json);
const prev     = $node['Event Router'].json;

// ── Extract info dari pinned message ──────────────────────────
const pinnedMsg = messages.find(m => m.pinned && m.content && !m.content.includes('COMMAND'));
let ticketInfo  = { ticketId: null, issue: 'Unknown', currentTimeline: '' };

if (pinnedMsg) {
  const c = pinnedMsg.content || '';
  // Format dari buildTicketInfoMessage() & buildIncidentInfoMessage()
  const idM = c.match(/#(\d+)_(Support|Incident)/);
  if (idM) ticketInfo.ticketId = idM[1];

  // Ambil judul: Title, Incident Information, atau Issue
  const issM =
    c.match(/\*\*Title\s*:\*\*\s*(.+?)\n/) ||
    c.match(/\*\*Incident Information\s*:\*\*\s*(.+?)\n/) ||
    c.match(/\*\*Issue\s*:\*\*\s*(.+?)\n/);
  if (issM) ticketInfo.issue = issM[1].trim();

  // Timeline saat ini
  const tlM =
    c.match(/\*\*Action Taken:\*\*\s*([\s\S]*?)(?:\*\*Evidence|\*\*Summary|\*\*Handling|$)/) ||
    c.match(/\*\*Tindak Lanjut:\*\*\s*([\s\S]*?)(?:\*\*Evidence|\*\*Summary|$)/);
  if (tlM) ticketInfo.currentTimeline = tlM[1].trim();
}

if (!ticketInfo.ticketId) {
  // Fallback ke ticketId dari event router
  if (prev.ticketId) {
    ticketInfo.ticketId = String(prev.ticketId);
    console.log(`⚠️  [MONITOR] Pinned not found — using event ticketId: ${prev.ticketId}`);
  } else {
    console.log('⏭ [MONITOR] SKIP: No ticket ID found');
    return [];
  }
}

// ── Filter KETAT: hanya completed actions ────────────────────
const ACTION_VERBS = [
  // Indonesia — sudah selesai dikerjakan
  'berhasil','sudah diperbaiki','sudah diganti','sudah diupdate','sudah direstart',
  'sudah dicek','sudah dikonfigurasi','sudah diinstal','sudah diaktifkan',
  'sudah dimatikan','sudah dinyalakan','sudah dilakukan','sudah selesai',
  'sudah dinormalisasi','sudah dinormalkan','kembali normal','normal kembali',
  'sudah berfungsi','berfungsi kembali','sudah terhubung','sudah online',
  'selesai diperbaiki','selesai dikonfigurasi','selesai diinstal',
  // English — completed actions
  'restarted','rebooted','configured','installed','updated','upgraded',
  'replaced','repaired','fixed','resolved','completed','deployed',
  'implemented','patched','rolled back','migrated','activated','deactivated',
  'reconfigured','reassigned','re-enabled','re-connected','verified','confirmed',
  'tested and working','back online','back to normal','issue resolved',
  'problem solved','now working','restored','recovered'
];

const DISQUALIFY_PATTERNS = [
  /^ok(e)?$/i, /^ya$/i, /^iya$/i, /^baik$/i, /^siap$/i, /^noted$/i,
  /^thanks?/i, /^terima\s*kasih/i, /^halo/i, /^hi$/i, /^hello$/i,
  /^\?+$/, /^tolong/i, /^mohon/i, /^coba\s*(cek|lihat)/i,
  /^ada\s*update/i, /^gimana/i, /^bagaimana/i, /^kapan/i, /^sudah\s*belum/i,
  /^masih\s*(proses|dicek|belum)/i, /^lagi\s*dicek/i,
  /^tunggu/i, /^sebentar/i, /^nanti/i, /^akan\s*(dicek|diperbaiki|dilakukan)/i,
  /^sedang\s*(dicek|diperbaiki|proses)/i, /^lagi\s*(diperbaiki|cek)/i,
  /^mau\s*(coba|restart|cek)/i, /^coba\s*(restart|reboot|reset)/i
];

function isActionCompleted(content) {
  if (!content || content.length < 15) return false;
  const lower = content.toLowerCase();
  for (const p of DISQUALIFY_PATTERNS) {
    if (p.test(content.trim())) return false;
  }
  for (const kw of ACTION_VERBS) {
    if (lower.includes(kw)) return true;
  }
  return false;
}

const allMsgs = messages.filter(m =>
  m.author && !m.author.bot && !m.pinned &&
  m.content && m.content.length > 10 &&
  !m.content.startsWith('!') &&
  !m.content.includes('COMMAND') &&
  !m.content.includes('🤖')
);

const actionMsgs = allMsgs
  .filter(m => isActionCompleted(m.content))
  .map(m => ({
    author:    m.author.username || m.author.global_name || 'User',
    content:   m.content,
    timestamp: m.timestamp
  }));

console.log(`📝 [MONITOR] Ticket #${prev.ticketId}: ${allMsgs.length} msgs → ${actionMsgs.length} completed actions`);

if (actionMsgs.length < 1) {
  console.log('⏭ [MONITOR] SKIP: No completed action messages');
  return [];
}

return [{ json: {
  threadId:        prev.threadId,
  threadName:      prev.threadName,
  ticketType:      prev.ticketType,
  ticketId:        ticketInfo.ticketId,
  ticketIssue:     ticketInfo.issue,
  currentTimeline: ticketInfo.currentTimeline,
  discussions:     actionMsgs.reverse().slice(0, 15),
  totalMessages:   allMsgs.length,
  actionCount:     actionMsgs.length,
  mode:            'MONITORING'
}}];

// ================================================================
// EXTRACT (CLOSING MODE) — v4 + Repair Detection
// Prisma fix:
//   - Cek DB via GET /api/ticket/:id
//   - Response field: ticket.summaryTicket (camelCase dari normalizeTicket)
//   - ticketInfo.ticketId fallback ke event router jika pinned tidak ada
//   - discordHasSummary cek format message dari discord.service.js:
//       buildTicketInfoMessage  → "**Summary:**"
//       buildIncidentInfoMessage → "**Handling:**" (bukan Summary)
// ================================================================
const messages = $input.all().map(i => i.json);
const prev     = $node['Event Router'].json;

// ── Extract info dari pinned message ──────────────────────────
const pinnedMsg = messages.find(m => m.pinned && m.content && !m.content.includes('COMMAND'));
let ticketInfo  = {
  ticketId:         null,
  issue:            'Unknown',
  timeline:         '',
  discordHasSummary: false
};

if (pinnedMsg) {
  const c = pinnedMsg.content || '';

  // Ticket ID — format dari buildTicketInfoMessage/buildIncidentInfoMessage
  const idM = c.match(/#(\d+)_(Support|Incident)/);
  if (idM) ticketInfo.ticketId = idM[1];

  // Judul tiket
  const issM =
    c.match(/\*\*Title\s*:\*\*\s*(.+?)\n/) ||
    c.match(/\*\*Incident Information\s*:\*\*\s*(.+?)\n/) ||
    c.match(/\*\*Issue\s*:\*\*\s*(.+?)\n/);
  if (issM) ticketInfo.issue = issM[1].trim();

  // Timeline dari Discord
  const tlM =
    c.match(/\*\*Action Taken:\*\*\s*([\s\S]*?)(?:\*\*Evidence|\*\*Handling|$)/) ||
    c.match(/\*\*Tindak Lanjut:\*\*\s*([\s\S]*?)(?:\*\*Evidence|\*\*Summary|$)/);
  if (tlM) ticketInfo.timeline = tlM[1].trim();

  // Cek apakah summary/handling sudah tampil di Discord
  // INCIDENT → "**Handling:**" | TICKETING → "**Summary:**"
  ticketInfo.discordHasSummary =
    c.includes('**Summary:**') ||
    c.includes('**Handling:**') ||
    c.includes('📋 **Summary:**') ||
    c.includes('📋 **Handling:**');
}

// Fallback ticketId dari event router
if (!ticketInfo.ticketId) {
  if (prev.ticketId) {
    ticketInfo.ticketId = String(prev.ticketId);
    console.log(`⚠️  [CLOSING] Pinned not found — fallback ticketId: ${prev.ticketId}`);
  } else {
    console.log('⏭ [CLOSING] SKIP: No ticket ID');
    return [];
  }
}

// ── Cek DB via API — apakah summary sudah ada di database ─────
// FIX PRISMA: response ticket menggunakan camelCase:
//   ticket.summaryTicket (bukan ticket.summary_ticket)
//   ticket.rootCause     (bukan ticket.root_cause)
let dbSummary  = null;
let dbRootCause = null;
try {
  const dbRes = await $httpRequest({
    method: 'GET',
    url:    `http://backend:3000/api/ticket/${ticketInfo.ticketId}`,
    headers: { 'X-API-Key': 'automation_ticketing01_incident02' }
  });
  // Response: { success: true, ticket: { summaryTicket, rootCause, ... } }
  dbSummary   = dbRes?.ticket?.summaryTicket || null;
  dbRootCause = dbRes?.ticket?.rootCause     || null;
  console.log(`🗄️  [CLOSING] DB summaryTicket exists: ${!!dbSummary} | rootCause: ${!!dbRootCause}`);
} catch (e) {
  console.warn(`⚠️  [CLOSING] DB fetch failed: ${e.message}`);
}

// ── Decision Tree ──────────────────────────────────────────────
// C: Ada di DB DAN di Discord → fully synced → STOP
if (dbSummary && ticketInfo.discordHasSummary) {
  console.log('⏭ [CLOSING] SKIP: Summary fully synced (DB + Discord)');
  return [];
}

// B: Ada di DB tapi BELUM di Discord → REPAIR (skip AI generation)
if (dbSummary && !ticketInfo.discordHasSummary) {
  console.log(`🔧 [CLOSING] REPAIR: summaryTicket in DB but Discord not synced`);
  return [{ json: {
    threadId:   prev.threadId,
    ticketId:   ticketInfo.ticketId,
    ticketType: prev.ticketType,
    mode:       'REPAIR'
  }}];
}

// A: Belum ada di DB → normal CLOSING (generate via AI)
// Pastikan ada timeline untuk AI
if (!ticketInfo.timeline) {
  console.log('⏭ [CLOSING] SKIP: No timeline available for AI');
  return [];
}

// ── Filter diskusi relevan untuk AI ───────────────────────────
const CLOSING_KEYWORDS = [
  'selesai','resolved','completed','fixed','solved','berhasil',
  'sudah normal','sudah berfungsi','sudah diperbaiki','kembali normal',
  'tidak ada masalah','working now','problem solved','issue fixed',
  'berfungsi kembali','sudah teratasi','sudah dinormalisasi','restored'
];

const DISQUALIFY = [
  /^ok(e)?$/i, /^ya$/i, /^iya$/i, /^baik$/i, /^siap$/i, /^noted$/i,
  /^thanks?/i, /^terima\s*kasih/i, /^\?+$/
];

function isClosingRelevant(c) {
  if (!c || c.length < 15) return false;
  for (const p of DISQUALIFY) if (p.test(c.trim())) return false;
  const lower = c.toLowerCase();
  for (const kw of CLOSING_KEYWORDS) if (lower.includes(kw)) return true;
  if (c.length >= 40) return true;
  return false;
}

const allMsgs = messages.filter(m =>
  m.author && !m.author.bot && !m.pinned &&
  m.content && !m.content.startsWith('!') &&
  !m.content.includes('COMMAND') && !m.content.includes('🤖')
);

const relevant = allMsgs
  .filter(m => isClosingRelevant(m.content))
  .map(m => ({
    author:    m.author.username || m.author.global_name || 'User',
    content:   m.content,
    timestamp: m.timestamp
  }));

console.log(`📝 [CLOSING] ${allMsgs.length} msgs → ${relevant.length} relevant for AI`);

if (relevant.length < 2) {
  console.log(`⏭ [CLOSING] SKIP: Insufficient messages (${relevant.length} < 2)`);
  return [];
}

console.log(`✅ [CLOSING] PROCEED TO AI: ${relevant.length} msgs, ticket #${ticketInfo.ticketId}`);

return [{ json: {
  threadId:        prev.threadId,
  threadName:      prev.threadName,
  ticketType:      prev.ticketType,
  ticketId:        ticketInfo.ticketId,
  ticketIssue:     ticketInfo.issue,
  timeline:        ticketInfo.timeline,
  discussions:     relevant.reverse().slice(0, 30),
  discussionCount: relevant.length,
  mode:            'CLOSING'
}}];

// ================================================================
// BUILD AI PROMPT — handle REPAIR bypass + MONITORING + CLOSING
// Tidak ada perubahan konsep — hanya penguatan guard dan komentar.
// ================================================================
const data = $input.first().json;
const mode = (data.mode || '').toUpperCase();

if (!mode) return [];

// ── REPAIR: pass-through tanpa AI generation ──────────────────
// Data summaryTicket sudah ada di DB, hanya perlu Discord sync via repair-discord
if (mode === 'REPAIR') {
  console.log(`🔧 [BUILD] REPAIR mode — Ticket #${data.ticketId} (skip AI)`);
  return [{ json: {
    threadId:   data.threadId,
    ticketId:   data.ticketId,
    ticketType: data.ticketType,
    mode:       'REPAIR',
    prompt:     `Return exactly this JSON without any extra text: {"mode":"REPAIR","ticketId":"${data.ticketId}"}`
  }}];
}

if (mode !== 'MONITORING' && mode !== 'CLOSING') return [];

// ── Format discussion messages ────────────────────────────────
const msgsText = (data.discussions || []).map((m, i) =>
  `[${i + 1}] ${m.author} (${m.timestamp}): ${m.content}`
).join('\n');

console.log(`🤖 [BUILD] ${mode} prompt for Ticket #${data.ticketId} (${data.ticketType})`);

// ── MONITORING prompt ─────────────────────────────────────────
// Tugas: ekstrak NEW completed actions → append ke timeline di DB
// API target: POST /api/ticket/timeline/append
//   { ticketId, ticketType, newTimeline: [{ datetime, action }] }
if (mode === 'MONITORING') {
  const prompt = `You are a precise IT support timeline extractor. Timezone: WIB (Asia/Jakarta, UTC+7).

CURRENT TIMELINE (already recorded in DB — DO NOT duplicate):
${data.currentTimeline || '(Empty — no entries yet)'}

NEW MESSAGES (pre-filtered completed actions only):
${msgsText}

TASK: Extract ONLY NEW completed technical actions NOT already in the current timeline above.
Each action must be a CONCRETE COMPLETED step that contributed to resolving the issue.
Do NOT include: discussions, questions, status checks, future plans, or acknowledgements.

OUTPUT (valid JSON only — no markdown, no explanation):
{
  "shouldUpdate": true,
  "newTimeline": [
    { "datetime": "HH:MM WIB, DD/MM/YYYY", "action": "Specific completed action description" }
  ]
}

If nothing new to add: { "shouldUpdate": false, "newTimeline": [] }

RULES:
- Convert message timestamp to WIB 24-hour format
- English only, professional, concise
- Max 2 sentences per action entry
- Only COMPLETED actions — never plans or ongoing work`;

  return [{ json: {
    threadId:   data.threadId,
    ticketId:   data.ticketId,
    ticketType: data.ticketType,
    mode:       'MONITORING',
    prompt
  }}];
}

// ── CLOSING prompt ────────────────────────────────────────────
// Tugas: generate summary + rootCause + keywords
// API target: POST /api/ticket/summary
//   { ticketId, summary, rootCause, keywords }
// Prisma field mapping:
//   summary   → DB: summary_ticket  | Discord: **Summary:** (TICKETING) / **Handling:** (INCIDENT)
//   rootCause → DB: root_cause      | Discord: TIDAK tampil (hanya via chatbot)
//   keywords  → DB: search_keywords | Digunakan untuk pencarian tiket serupa
if (mode === 'CLOSING') {
  const prompt = `You are an IT resolution analyst. Analyze this resolved ticket and generate a concise professional summary.

TICKET INFO:
- Type: ${data.ticketType}
- Issue: ${data.ticketIssue}

TIMELINE OF ACTIONS TAKEN:
${data.timeline}

CLOSING DISCUSSION:
${msgsText}

TASK: Generate summary, root cause, and search keywords for this resolved ticket.

OUTPUT (valid JSON only — no markdown, no explanation, directly parseable):
{
  "summary": "2-3 sentences describing HOW the issue was resolved and what actions were taken",
  "rootCause": "Specific technical cause of the issue — be precise and technical",
  "keywords": ["keyword1", "keyword2", "keyword3", "keyword4", "keyword5"]
}

RULES:
- English only, professional, concise
- summary: focus on RESOLUTION (not the problem itself)
- rootCause: be technically specific (e.g. 'Switch port 24 misconfigured VLAN 10' not 'network issue')
- keywords: 3-6 lowercase words for similarity search
- Total response under 300 words`;

  return [{ json: {
    threadId:    data.threadId,
    ticketId:    data.ticketId,
    ticketType:  data.ticketType,
    ticketIssue: data.ticketIssue,
    timeline:    data.timeline,
    mode:        'CLOSING',
    prompt
  }}];
}

return [];

// ================================================================
// PARSE & ROUTE OUTPUT — handle REPAIR bypass
// Prisma fix:
//   - MONITORING output → POST /api/ticket/timeline/append
//     body: { ticketId (Number), ticketType, newTimeline: [{datetime, action}] }
//   - CLOSING output  → POST /api/ticket/summary
//     body: { ticketId (Number), summary, rootCause, keywords }
//   - REPAIR output   → POST /api/ticket/repair-discord
//     body: { ticketId (Number) }
//   - ticketId selalu dikirim sebagai Number (bukan String)
//     karena schema Prisma: id Int @id @default(autoincrement())
// ================================================================
const aiResp = $input.first().json;
const src    = $('Build AI Prompt').first().json;
const mode   = (src.mode || '').toUpperCase();
const aiOut  = aiResp.output || aiResp.text || '';

console.log(`=== [PARSE] mode: ${mode} | AI output len: ${aiOut.length} | ticketId: ${src.ticketId}`);

// ── REPAIR: bypass AI — route ke repair-discord endpoint ──────
if (mode === 'REPAIR') {
  console.log('🔧 [PARSE] REPAIR — routing to repair-discord endpoint');
  return [{ json: {
    threadId:   src.threadId,
    ticketId:   Number(src.ticketId),
    ticketType: src.ticketType,
    mode:       'REPAIR'
  }}];
}

if (mode !== 'MONITORING' && mode !== 'CLOSING') {
  console.log(`⚠️  [PARSE] Unknown mode: ${mode}`);
  return [{ json: { error: 'Invalid mode', mode } }];
}

if (!aiOut.trim()) {
  console.log(`⚠️  [PARSE] Empty AI output for mode: ${mode}`);
  return [{ json: { error: 'Empty AI output', mode } }];
}

// ── Parse JSON dari AI output ──────────────────────────────────
try {
  // Strip markdown code fences jika ada
  let cleaned = aiOut.trim()
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/gi, '');

  // Ekstrak JSON object (dari { hingga })
  const s = cleaned.indexOf('{');
  const e = cleaned.lastIndexOf('}');
  if (s === -1 || e === -1) {
    console.log(`⚠️  [PARSE] No JSON object found in AI output`);
    return [{ json: { error: 'No JSON found in AI output', mode, rawOutput: aiOut.substring(0, 200) } }];
  }

  const parsed = JSON.parse(cleaned.substring(s, e + 1));
  console.log(`✅ [PARSE] JSON parsed OK — keys: ${Object.keys(parsed).join(', ')}`);

  // ── MONITORING: extract newTimeline entries ──────────────────
  if (mode === 'MONITORING') {
    if (!parsed.hasOwnProperty('shouldUpdate')) {
      return [{ json: { error: 'Missing shouldUpdate in AI output', mode } }];
    }
    if (!parsed.shouldUpdate || !Array.isArray(parsed.newTimeline) || parsed.newTimeline.length === 0) {
      console.log('⏭ [PARSE] MONITORING: No new timeline entries to add');
      return [];
    }
    // Validasi setiap entry memiliki datetime & action
    const validEntries = parsed.newTimeline.filter(e => e && e.datetime && e.action);
    if (validEntries.length === 0) {
      console.log('⏭ [PARSE] MONITORING: newTimeline entries invalid (missing datetime/action)');
      return [];
    }
    console.log(`✅ [PARSE] MONITORING: ${validEntries.length} valid entries for ticket #${src.ticketId}`);
    return [{ json: {
      threadId:    src.threadId,
      ticketId:    Number(src.ticketId),
      ticketType:  src.ticketType,
      newTimeline: validEntries,
      mode:        'MONITORING'
    }}];
  }

  // ── CLOSING: extract summary, rootCause, keywords ────────────
  if (mode === 'CLOSING') {
    if (!parsed.summary || !parsed.rootCause) {
      console.log('⚠️  [PARSE] CLOSING: Missing summary or rootCause in AI output');
      return [{ json: { error: 'Missing summary or rootCause in AI output', mode, keys: Object.keys(parsed) } }];
    }
    console.log(`✅ [PARSE] CLOSING: summary & rootCause ready for ticket #${src.ticketId}`);
    return [{ json: {
      threadId:    src.threadId,
      ticketId:    Number(src.ticketId),
      ticketType:  src.ticketType,
      ticketIssue: src.ticketIssue,
      timeline:    src.timeline,
      summary:     String(parsed.summary).trim(),
      rootCause:   String(parsed.rootCause).trim(),
      keywords:    Array.isArray(parsed.keywords) ? parsed.keywords.map(String) : [],
      mode:        'CLOSING'
    }}];
  }

  return [];

} catch (err) {
  console.error(`❌ [PARSE] JSON parse exception: ${err.message}`);
  return [{ json: {
    error:     'JSON parse exception',
    message:   err.message,
    mode,
    rawOutput: aiOut.substring(0, 300)
  }}];
}
